integer k;
always @(*) begin
  for (k = 0; k < 4; k = k + 1)
    out[k] = in[k];
  // k should equal 4 here
  out[7:4] = {4{in[k]}};
end

integer k;
reg [7:0] out;
reg [3:0] in;
always @(*) begin
  for (k = 0; k < 4; k = k + 1)
    out[k] = in[k];
  out[4] = in[k]; // k == 4 post-loop
end
